/* Method verified as working as of 25 June 2026, Time 08:38:39 PM UTC /*

alias test { dialog -m test test }

dialog test {
  title ""
  option pixels
  size -1 -1 306 156
  text "Enter or select the modes to delete:", 1, 10 12 290 16
  combo 2, 8 92 290 120, sort edit drop result
  button "&OK", 3, 141 125 76 23, ok default
  button "&Cancel", 4, 223 125 76 23, cancel
}
on *:dialog:test:*:*:{
  if ($devent == init) {
    var %i 1,%g +n,+t,+T,+P,%f +t,%r $numtok(%g,44)
    while (%i <= %r) {
      did -a $dname 2 $gettok(%g,%i,44)
      if ($gettok(%g,%i,44) != %f) { did -co $dname 2 0 %f | did -f $dname 2 }
      inc %i
    }
  }
}

import requests
from functools import partial
from itertools import cycle
from random import randint
from typing import Any

# todo: convert_func definiert den Typen des Rückgabewerts der Funktion isu
       
_global_cid_generator = cycle(range(1, 0xFFFFFFFF))

def convert_hex(x: str) -> int:
    return int(x, 16)


def convert_not[T](x: T) -> T:
    return x


def isu(ip, index: int, subindex: int = 0, convert_func=convert_not, cid_generator=_global_cid_generator) -> Any:
    cid = next(cid_generator)

    response = requests.post(
		url=f"http://{ip}/iolinkmaster",
		json={
			"code": "request",
			"cid": cid,
			"adr": "/iolinkmaster/port[2]/iolinkdevice/iolreadacyclic",
			"data": {
				"index": index,
				"subindex": subindex,
			},
		},
	)
    response.raise_for_status()
    data = response.json()

    try:
        if int(data.get("code")) != 200:
            raise RuntimeError("code != 200", data)
    except ValueError:
        raise RuntimeError("code is not an integer", data)

    if data.get("cid") != cid:
        raise RuntimeError("Got wrong answer", data)

    return convert_func(data["data"]["value"])


isu("192.168.0.3", 542)

# --- Configuration -----------------------------------------------------------
$ApiUrl        = 'https://socradar.io/free-tools/api/fortibleed/search-fortibleed'
$InputFile     = 'ftglist.txt'
$OutputFile    = 'results.csv'
$BaseDelay     = 10  # seconds between requests
$MaxExtraDelay = 5   # max additional random seconds added to BaseDelay

# Paste your browser cookie string here if you get 401/403 responses.
# Firefox: F12 -> Network -> trigger a check -> click the POST request ->
#          Headers tab -> copy the full 'Cookie' request header value.
$Cookie = ''
# -----------------------------------------------------------------------------

$entries = Get-Content -Path $InputFile |
    Where-Object { $_ -match '\S' } |
    ForEach-Object {
        if ($_ -match '^\d+\t(.+)$') { $Matches[1].Trim() } else { $_.Trim() }
    }

if (-not $entries) {
    Write-Warning "No entries found in $InputFile. Exiting."
    exit 1
}

$results = [System.Collections.Generic.List[PSCustomObject]]::new()

for ($i = 0; $i -lt $entries.Count; $i++) {
    $entry = $entries[$i]
    Write-Host "[$($i + 1)/$($entries.Count)] Checking: $entry"

    $requestParams = @{
        Uri         = $ApiUrl
        Method      = 'Post'
        Body        = (@{ query = $entry } | ConvertTo-Json -Compress)
        ContentType = 'application/json'
        Headers     = @{
            'Accept'  = 'application/json'
            'Referer' = 'https://socradar.io/free-tools/fortibleed'
            'Origin'  = 'https://socradar.io'
        }
    }

    if ($Cookie) {
        $requestParams.Headers['Cookie'] = $Cookie
    }

    $detected = 'error'
    try {
        $response = Invoke-RestMethod @requestParams
        $detected = [string]$response.data.is_detected
    } catch {
        Write-Warning "  Request failed: $_"
    }

    Write-Host "  Detected: $detected"

    $results.Add([PSCustomObject]@{
        IPorURL  = $entry
        Detected = $detected
    })

    if ($i -lt $entries.Count - 1) {
        $delay = $BaseDelay + (Get-Random -Minimum 0 -Maximum ($MaxExtraDelay + 1))
        Write-Host "  Waiting $delay seconds before next request...`n"
        Start-Sleep -Seconds $delay
    }
}

$results | Export-Csv -Path $OutputFile -NoTypeInformation -append
Write-Host "`nDone. Results saved to $OutputFile"

